const MAX_TEMPLATE_FILE_SIZE: u64 = 64 * 1024;

pub fn load_and_validate_custom_template(path: &str) -> anyhow::Result<Vec<u8>> {
    let metadata = std::fs::metadata(path)
        .map_err(|e| anyhow::anyhow!("Failed to read ClientHello template metadata ({}): {}", path, e))?;
    if metadata.len() > MAX_TEMPLATE_FILE_SIZE {
        anyhow::bail!(
            "Template file too large: {} bytes (max {})",
            metadata.len(),
            MAX_TEMPLATE_FILE_SIZE
        );
    }

    let raw_str = std::fs::read_to_string(path)
        .map_err(|e| anyhow::anyhow!("Failed to read ClientHello template ({}): {}", path, e))?;

    parse_template_hex_string(&raw_str)
}

pub(crate) fn parse_template_hex_string(raw_str: &str) -> anyhow::Result<Vec<u8>> {
    let cleaned = clean_template_hex(raw_str);

    if !cleaned.len().is_multiple_of(2) {
        anyhow::bail!("Invalid hex format: odd length after cleaning ({} bytes)", cleaned.len());
    }

    let bytes = hex::decode(&cleaned)
        .map_err(|e| anyhow::anyhow!("Hex decode failed for template: {}", e))?;

    Ok(bytes)
}

fn clean_template_hex(raw_str: &str) -> String {
    raw_str
        .replace("0x", "")
        .replace("0X", "")
        .chars()
        .filter(|c| !c.is_whitespace() && !" ,:;[](){}".contains(*c))
        .collect()
}

